cd /tmp/sv-3bd37fd370524111821991bf52e95b53/moderate-msbuild-properties && dotnet list Platform.sln package --format json 2>/dev/null | python3 -c "
import json, sys
data = json.load(sys.stdin)
for p in data['projects']:
    name = p['path'].split('/')[-1]
    for fw in p['frameworks']:
        for pkg in fw.get('topLevelPackages', []):
            print(f'{name}  {pkg[\"id\"]:55s} {pkg[\"resolvedVersion\"]}')
"

